/**
 * Get emoji by name with fallback
 * @param {string} name - Emoji name
 * @param {string} fallback - Fallback emoji or string
 * @returns {string} Emoji or fallback
 */
emojis.get = (name, fallback = '') => {
  return emojis[name] || fallback;
};

/**
 * Check if emoji exists
 * @param {string} name - Emoji name
 * @returns {boolean} True if exists
 */
emojis.has = (name) => {
  return emojis.hasOwnProperty(name);
};

/**
 * Get all emoji names
 * @returns {string[]} Array of emoji names
 */
emojis.list = () => {
  return Object.keys(emojis).filter(key => 
    typeof emojis[key] === 'string' && !['get', 'has', 'list'].includes(key)
  );
};

module.exports = emojis;